370              "Existing range must be a subset of NewR");
371       Range = std::move(NewR);
372       return true;
373     }
374 
375     assert(isUnknown() || isUndef());
376 
377     NumRangeExtensions = 0;
378     Tag = NewTag;
379     new (&Range) ConstantRange(std::move(NewR));
380     return true;
381   }
